import { execSync } from 'child_process';
import fs from 'fs';
const W='', PREP='';
const FILES={'assets/pet-form.js':'','assets/pet-profile.js':''};
const TOKG=process.env.GH_TOKEN, REPO=process.env.GH_REPO||'raimis079-creator/petshop-bridge';
const U=process.env.WP_USER||'', P=(process.env.WP_APP_PASS||'').replace(/\s+/g,'');
const AUTH='-u "'+U+':'+P+'"';
function wj(m,path,body){fs.writeFileSync('/tmp/wb.json', JSON.stringify(body));
  return execSync('curl -sk '+AUTH+' -X '+m+' -H "Content-Type: application/json" --data-binary @/tmp/wb.json "https://dev.avesa.lt/wp-json/'+path+'"',{maxBuffer:50*1024*1024,timeout:70000}).toString();}
function putB64(name,b64){const u='https://api.github.com/repos/'+REPO+'/contents/screenshots/'+name;let s='';
 for(let i=0;i<5;i++){try{const j=JSON.parse(execSync('curl -s -H "Authorization: Bearer '+TOKG+'" "'+u+'?n='+Math.random()+'"',{maxBuffer:50*1024*1024}).toString());if(j.sha)s=j.sha;}catch(e){}
  fs.writeFileSync('/tmp/pj.json',JSON.stringify({message:'r',content:b64,...(s?{sha:s}:{})}));
  const c=execSync('curl -s -o /dev/null -w "%{http_code}" -X PUT -H "Authorization: Bearer '+TOKG+'" -d @/tmp/pj.json "'+u+'"',{maxBuffer:50*1024*1024}).toString().trim();
  if(c==='200'||c==='201')return c; execSync('sleep 2');}return 'fail';}
const o={};
const mk=wj('POST','code-snippets/v1/snippets',{name:'FIX220 (temp)',code:Buffer.from(W,'base64').toString('utf8'),scope:'front-end',active:true,priority:5});
let sid; try{sid=JSON.parse(mk).id;}catch(e){o.mkerr=String(mk).slice(0,150);}
execSync('sleep 3');
fs.writeFileSync('/tmp/payload.json', JSON.stringify({files:FILES}));
try{const r=execSync('curl -sk -X POST -H "Content-Type: application/json" --data-binary @/tmp/payload.json "https://dev.avesa.lt/?ps_dep218=Dp218x"',{maxBuffer:20*1024*1024,timeout:90000}).toString();
  o.write=r.slice(r.indexOf('{'),r.lastIndexOf('}')+1);}catch(e){o.write='ERR';}
if(sid){ try{wj('POST','code-snippets/v1/snippets/'+sid,{active:false});}catch(e){} try{execSync('curl -sk '+AUTH+' -X DELETE "https://dev.avesa.lt/wp-json/code-snippets/v1/snippets/'+sid+'"');}catch(e){} }
const mk2=wj('POST','code-snippets/v1/snippets',{name:'VIS220 (temp)',code:Buffer.from(PREP,'base64').toString('utf8'),scope:'front-end',active:true,priority:5});
let sid2; try{sid2=JSON.parse(mk2).id;}catch(e){}
execSync('sleep 3');
try{const r=execSync('curl -sk "https://dev.avesa.lt/?ps_ontrows=E2eTmp9x"',{timeout:30000}).toString();o.ont=r.slice(r.indexOf('{'),r.lastIndexOf('}')+1).slice(0,1500);}catch(e){o.ont='ERR';}
try{execSync('curl -sk "https://dev.avesa.lt/?ps_e2eprep=E2eTmp9x"',{timeout:40000});}catch(e){}
try{
  const { chromium } = await import('playwright');
  const browser = await chromium.launch();
  const ctx = await browser.newContext({viewport:{width:1440,height:1400}, ignoreHTTPSErrors:true});
  const page = await ctx.newPage();
  page.on('pageerror', e=>{(o.console=o.console||[]).push(String(e).slice(0,120));});
  await page.goto('https://dev.avesa.lt/?ps_alogin=E2eTmp9x',{waitUntil:'networkidle',timeout:60000});
  await page.waitForTimeout(1500);
  await page.evaluate(()=>{const b=[...document.querySelectorAll('button,a')].find(x=>x.textContent.trim()==='PRIIMTI');if(b)b.click();});
  await page.waitForTimeout(3000);
  // E2E Pusiau (B busena - maisto nera) -> Mityba Atidaryti -> paieska -> priskirti -> AR LIEKAM MODULYJE?
  await page.evaluate(()=>{const t=document.querySelectorAll('.pspet-switch-item'); for(const x of t){ if(/Pusiau/.test(x.innerText)){x.click();return;} }});
  await page.waitForTimeout(3000);
  await page.evaluate(()=>{const b=[...document.querySelectorAll('button')].find(x=>x.textContent.trim()==='Atidaryti');if(b)b.click();});
  await page.waitForTimeout(2500);
  // paieskos laukas
  o.search=await page.evaluate(()=>{
    const i=[...document.querySelectorAll('input')].find(x=>/Ieškokite|paieška|pavadinim/i.test(x.placeholder||'')); 
    if(!i) return 'NO SEARCH INPUT';
    const setter=Object.getOwnPropertyDescriptor(HTMLInputElement.prototype,'value').set;
    setter.call(i,'Josera'); i.dispatchEvent(new Event('input',{bubbles:true})); return 'OK';
  });
  await page.waitForTimeout(2500);
  o.pick=await page.evaluate(()=>{
    const b=[...document.querySelectorAll('button')].find(x=>/Pasirinkti|Priskirti/.test(x.textContent));
    if(b){b.click();return b.textContent.trim();}
    const r=[...document.querySelectorAll('.pspet-profile *')].filter(x=>/Josera/.test(x.textContent)&&x.children.length===0).slice(0,3).map(x=>x.textContent.trim());
    return 'NO BTN; matoma: '+r.join(' | ');
  });
  await page.waitForTimeout(4000);
  o.po_priskyrimo=await page.evaluate(()=>document.querySelector('.pspet-profile') ? document.querySelector('.pspet-profile').innerText.replace(/\s+/g,' ').slice(0,300):'');
  const b1=await page.screenshot({fullPage:true}); putB64('y_1_po_maisto_keitimo.png', b1.toString('base64'));
  // birthField LT: atidarom step2
  await page.evaluate(()=>{const b=[...document.querySelectorAll('button')].find(x=>/Grįžti į augintinio/.test(x.textContent));if(b)b.click();});
  await page.waitForTimeout(2500);
  await page.evaluate(()=>{const b=[...document.querySelectorAll('button')].find(x=>x.textContent.trim()==='Tęsti');if(b)b.click();});
  await page.waitForTimeout(1500);
  o.birth_lt=await page.evaluate(()=>{
    const h=document.getElementById('pspet-form-host'); if(!h) return 'NO HOST';
    const sels=[...h.querySelectorAll('select')];
    return sels.length+' selectai: '+sels.map(s=>s.options[0].textContent+'..'+(s.options[1]?s.options[1].textContent:'')).join(' | ');
  });
  o.breed_count=await page.evaluate(()=>{
    const h=document.getElementById('pspet-form-host'); const dl=h&&h.querySelector('datalist');
    return dl? dl.options.length : 'NO DATALIST';
  });
  await browser.close();
}catch(e){ o.err=String(e).slice(0,300); }
try{execSync('curl -sk "https://dev.avesa.lt/?ps_e2eclean=E2eTmp9x"',{timeout:30000});}catch(e){}
if(sid2){ try{wj('POST','code-snippets/v1/snippets/'+sid2,{active:false});}catch(e){} try{execSync('curl -sk '+AUTH+' -X DELETE "https://dev.avesa.lt/wp-json/code-snippets/v1/snippets/'+sid2+'"');}catch(e){} }
putB64('fix220.json', Buffer.from(JSON.stringify(o)).toString('base64'));
console.log('done');
